package com.schoolbus.controller;
import com.schoolbus.dto.request.*;import com.schoolbus.dto.response.*;import com.schoolbus.service.AdminCrudService;import jakarta.validation.Valid;import org.springframework.data.domain.*;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/admin/students") public class AdminStudentController{private final AdminCrudService s;public AdminStudentController(AdminCrudService s){this.s=s;}@GetMapping public ApiResponse<PageResponse<StudentResponse>> list(@RequestParam(required=false)String search,@RequestParam(required=false)String grade,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size,@RequestParam(defaultValue="id")String sort){return ApiResponse.success(PageResponse.from(s.students(search,grade,PageRequest.of(page,size,Sort.by(sort)))));}@GetMapping("/{id}")public ApiResponse<StudentResponse> get(@PathVariable Long id){return ApiResponse.success(s.student(id));}@PostMapping public ResponseEntity<ApiResponse<StudentResponse>> create(@Valid @RequestBody StudentRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success("Student created",s.createStudent(r)));}@PutMapping("/{id}")public ApiResponse<StudentResponse> update(@PathVariable Long id,@Valid @RequestBody StudentRequest r){return ApiResponse.success(s.updateStudent(id,r));}@PatchMapping("/{id}/deactivate")public ApiResponse<Void> deactivate(@PathVariable Long id){s.deactivateStudent(id);return ApiResponse.success("Student deactivated",null);}}
